import { createContext, useContext, useEffect, useState, type ReactNode } from 'react'
import type { User, Session } from '@supabase/supabase-js'
import { supabase } from '../lib/supabase'

interface AuthContextType {
  user: User | null
  session: Session | null
  loading: boolean
  signIn: (email: string, password: string) => Promise<{ error: Error | null }>
  signOut: () => Promise<void>
  setUser: (user: User | null) => void
}

const AuthContext = createContext<AuthContextType | undefined>(undefined)

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<User | null>(null)
  const [session, setSession] = useState<Session | null>(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session)
      setUser(session?.user ?? null)
      setLoading(false)
    })

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session)
      setUser(session?.user ?? null)
      setLoading(false)
    })

    return () => subscription.unsubscribe()
  }, [])

  const signIn = async (email: string, password: string) => {
    const { error } = await supabase.auth.signInWithPassword({ email, password })
    return { error: error as Error | null }
  }

  const signOut = async () => {
    await supabase.auth.signOut()
  }

  return (
    <AuthContext.Provider value={{ user, session, loading, signIn, signOut, setUser }}>
      {children}
    </AuthContext.Provider>
  )
}


export function useAuth() {
  const context = useContext(AuthContext)
  if (!context) throw new Error('useAuth must be used within AuthProvider')
  return context
}

import { useCallback, useEffect, useState } from 'react'
import { supabase } from '../lib/supabase'
import { useRealtime } from '../hooks/useRealtime'

interface Categoria { id: string; nome: string; descricao: string; ordem: number; ativo: boolean }
interface Produto { id: string; categoria_id: string; nome: string; descricao: string; preco: number; disponivel: boolean; destaque: boolean; tempo_preparo: number; imagem_url: string }
interface PrecoTamanho { id: string; produto_id: string; tamanho: string; preco: number }

export default function CardapioAdminPage() {
  const [categorias, setCategorias] = useState<Categoria[]>([])
  const [produtos, setProdutos] = useState<Produto[]>([])
  const [tab, setTab] = useState<'categorias' | 'produtos'>('produtos')
  const [editProduto, setEditProduto] = useState<Partial<Produto> | null>(null)
  const [editCategoria, setEditCategoria] = useState<Partial<Categoria> | null>(null)
  const [precos, setPrecos] = useState<PrecoTamanho[]>([])
  const [showProdutoModal, setShowProdutoModal] = useState(false)
  const [showCategoriaModal, setShowCategoriaModal] = useState(false)
  const [draggedCategoria, setDraggedCategoria] = useState<string | null>(null)

  const fetchCategorias = useCallback(async () => {
    const { data } = await supabase.from('categorias').select('*').order('ordem')
    if (data) setCategorias(data)
  }, [])

  const fetchProdutos = useCallback(async () => {
    const { data } = await supabase.from('produtos').select('*').order('ordem')
    if (data) setProdutos(data)
  }, [])

  const fetchPrecos = useCallback(async (produtoId: string) => {
    const { data } = await supabase.from('precos_tamanho').select('*').eq('produto_id', produtoId)
    if (data) setPrecos(data)
  }, [])

  useEffect(() => { fetchCategorias(); fetchProdutos() }, [fetchCategorias, fetchProdutos])
  useRealtime('produtos', fetchProdutos)

  // ---- CRUD Categoria ----
  const saveCategoria = async () => {
    if (!editCategoria?.nome) return
    const { error } = editCategoria.id 
      ? await supabase.from('categorias').update({ nome: editCategoria.nome, descricao: editCategoria.descricao || '' }).eq('id', editCategoria.id)
      : await supabase.from('categorias').insert({ nome: editCategoria.nome, descricao: editCategoria.descricao || '', ordem: categorias.length })

    if (error) {
      console.error('Erro ao salvar categoria:', error)
      alert('Erro ao salvar: verifique se você está logado corretamente. (RLS)')
      return
    }

    setShowCategoriaModal(false)
    setEditCategoria(null)
    fetchCategorias()
  }

  const deleteCategoria = async (id: string) => {
    const { error } = await supabase.from('categorias').delete().eq('id', id)
    if (error) alert('Erro ao excluir: ' + error.message)
    fetchCategorias()
  }

  // ---- Reorganizar Categorias (Drag Drop) ----
  const handleDropCategoria = async (e: React.DragEvent, targetId: string) => {
    e.preventDefault()
    if (!draggedCategoria || draggedCategoria === targetId) return

    const draggedIdx = categorias.findIndex(c => c.id === draggedCategoria)
    const targetIdx = categorias.findIndex(c => c.id === targetId)

    const novasCategorias = [...categorias]
    const [item] = novasCategorias.splice(draggedIdx, 1)
    novasCategorias.splice(targetIdx, 0, item)

    // Atualiza otimista
    setCategorias(novasCategorias)
    setDraggedCategoria(null)

    // Salva a nova ordem no banco
    const updates = novasCategorias.map((c, idx) => 
      supabase.from('categorias').update({ ordem: idx }).eq('id', c.id)
    )
    await Promise.all(updates)
  }

  // ---- CRUD Produto ----
  const saveProduto = async () => {
    if (!editProduto?.nome) return
    const record = {
      nome: editProduto.nome,
      descricao: editProduto.descricao || '',
      preco: editProduto.preco || 0,
      categoria_id: editProduto.categoria_id || null,
      disponivel: editProduto.disponivel ?? true,
      destaque: editProduto.destaque ?? false,
      tempo_preparo: editProduto.tempo_preparo || 30,
    }
    const { error } = editProduto.id
      ? await supabase.from('produtos').update(record).eq('id', editProduto.id)
      : await supabase.from('produtos').insert({ ...record, ordem: produtos.length })

    if (error) {
      console.error('Erro ao salvar produto:', error)
      alert('Erro ao salvar: verifique se você está logado corretamente. (RLS)')
      return
    }

    setShowProdutoModal(false)
    setEditProduto(null)
    fetchProdutos()
  }

  const deleteProduto = async (id: string) => {
    const { error } = await supabase.from('produtos').delete().eq('id', id)
    if (error) alert('Erro ao excluir: ' + error.message)
    fetchProdutos()
  }

  const toggleDisponivel = async (p: Produto) => {
    await supabase.from('produtos').update({ disponivel: !p.disponivel }).eq('id', p.id)
    fetchProdutos()
  }

  // ---- Preços por tamanho ----
  const addPreco = async (produtoId: string, tamanho: string, preco: number) => {
    const { error } = await supabase.from('precos_tamanho').insert({ produto_id: produtoId, tamanho, preco })
    if (error) alert('Erro ao adicionar preço: ' + error.message)
    fetchPrecos(produtoId)
  }

  const deletePreco = async (precoId: string, produtoId: string) => {
    const { error } = await supabase.from('precos_tamanho').delete().eq('id', precoId)
    if (error) alert('Erro ao excluir preço: ' + error.message)
    fetchPrecos(produtoId)
  }


  return (
    <>
      <div className="animate-fade-in">
        <div className="mb-8 flex flex-col md:flex-row md:items-end justify-between gap-6">
          <div>
            <span className="text-secondary font-bold uppercase tracking-[0.3em] text-[10px] mb-2 block">Gestão</span>
            <h2 className="text-5xl font-headline font-bold text-on-background tracking-tighter">Cardápio</h2>
          </div>
          <div className="flex bg-[#1c1e26] p-1 rounded-xl border border-outline-variant/5">
            <button onClick={() => setTab('produtos')} className={`px-6 py-2 rounded-lg text-xs font-headline font-bold uppercase tracking-widest transition-all ${tab === 'produtos' ? 'bg-primary-container text-on-primary-fixed shadow-lg' : 'text-on-surface-variant hover:text-on-surface'}`}>Produtos</button>
            <button onClick={() => setTab('categorias')} className={`px-6 py-2 rounded-lg text-xs font-headline font-bold uppercase tracking-widest transition-all ${tab === 'categorias' ? 'bg-primary-container text-on-primary-fixed shadow-lg' : 'text-on-surface-variant hover:text-on-surface'}`}>Categorias</button>
          </div>
        </div>

        {tab === 'categorias' && (
          <div>
            <button onClick={() => { setEditCategoria({}); setShowCategoriaModal(true) }} className="mb-8 bg-primary-container text-on-primary-fixed px-8 py-4 rounded-xl font-headline font-bold text-xs uppercase tracking-widest flex items-center gap-2 hover:shadow-[0_0_20px_rgba(255,86,55,0.3)] active:scale-95 transition-all">
              <span className="material-symbols-outlined text-lg">add</span> Nova Categoria
            </button>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {categorias.map(c => (
                <div 
                  key={c.id} 
                  draggable
                  onDragStart={() => setDraggedCategoria(c.id)}
                  onDragOver={(e) => e.preventDefault()}
                  onDrop={(e) => handleDropCategoria(e, c.id)}
                  className={`bg-[#16181f] p-8 rounded-2xl border transition-all group cursor-grab active:cursor-grabbing relative overflow-hidden ${draggedCategoria === c.id ? 'border-primary-container opacity-50 scale-95 shadow-lg' : 'border-[#252830] hover:border-primary-container/30'}`}
                >
                  {/* Grip handler lateral */}
                  <div className="absolute left-0 top-0 bottom-0 w-2 bg-gradient-to-b from-transparent via-[#252830] to-transparent opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                    <span className="material-symbols-outlined text-outline-variant/50 text-xs">drag_indicator</span>
                  </div>
                  <div className="flex justify-between items-start pl-2">

                    <div>
                      <h4 className="font-headline font-bold text-xl text-on-surface">{c.nome}</h4>
                      <p className="text-xs text-on-surface-variant/60 mt-2 font-body leading-relaxed">{c.descricao}</p>
                    </div>
                    <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button onClick={() => { setEditCategoria(c); setShowCategoriaModal(true) }} className="w-8 h-8 flex items-center justify-center rounded-lg bg-surface-container-high text-primary hover:bg-primary hover:text-on-primary transition-all">
                        <span className="material-symbols-outlined text-lg">edit</span>
                      </button>
                      <button onClick={() => deleteCategoria(c.id)} className="w-8 h-8 flex items-center justify-center rounded-lg bg-surface-container-high text-error hover:bg-error hover:text-on-error transition-all">
                        <span className="material-symbols-outlined text-lg">delete</span>
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {tab === 'produtos' && (
          <div>
            <button onClick={() => { setEditProduto({}); setShowProdutoModal(true) }} className="mb-8 bg-primary-container text-on-primary-fixed px-8 py-4 rounded-xl font-headline font-bold text-xs uppercase tracking-widest flex items-center gap-2 hover:shadow-[0_0_20px_rgba(255,86,55,0.3)] active:scale-95 transition-all">
              <span className="material-symbols-outlined text-lg">add</span> Novo Produto
            </button>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
              {produtos.map(p => (
                <div key={p.id} className={`bg-[#16181f] p-6 rounded-2xl border border-[#252830] hover:border-primary-container/20 transition-all group flex flex-col ${!p.disponivel ? 'opacity-40 grayscale' : ''}`}>
                  <div className="flex justify-between items-start mb-4">
                    <div className="flex-1">
                      <h4 className="font-headline font-bold text-lg text-on-surface">{p.nome}</h4>
                      <span className="text-[10px] font-bold text-primary-container uppercase tracking-widest">
                        {categorias.find(c => c.id === p.categoria_id)?.nome || 'Sem Categoria'}
                      </span>
                    </div>
                    <span className="text-lg font-headline font-bold text-[#4ade80]">
                      {Number(p.preco).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                    </span>
                  </div>
                  <p className="text-xs text-on-surface-variant/60 font-body mb-6 flex-1 line-clamp-2">{p.descricao}</p>

                  <div className="flex items-center justify-between pt-4 border-t border-outline-variant/5">
                    <div className="flex gap-2">
                      <button onClick={() => { setEditProduto(p); setShowProdutoModal(true); fetchPrecos(p.id) }} className="w-8 h-8 flex items-center justify-center rounded-lg bg-surface-container-high text-primary hover:bg-primary hover:text-on-primary transition-all">
                        <span className="material-symbols-outlined text-lg">edit</span>
                      </button>
                      <button onClick={() => deleteProduto(p.id)} className="w-8 h-8 flex items-center justify-center rounded-lg bg-surface-container-high text-error hover:bg-error hover:text-on-error transition-all">
                        <span className="material-symbols-outlined text-lg">delete</span>
                      </button>
                    </div>
                    <button onClick={() => toggleDisponivel(p)} className={`text-[10px] font-bold px-3 py-1.5 rounded-full uppercase tracking-tighter transition-all ${p.disponivel ? 'bg-green-500/10 text-[#4ade80]' : 'bg-red-500/10 text-red-400'}`}>
                      {p.disponivel ? 'No Cardápio' : 'Esgotado'}
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      {/* Modais Movidos para fora do transform/container de animação */}
      {showCategoriaModal && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[999] flex items-center justify-center p-6" onClick={() => setShowCategoriaModal(false)}>
          <div className="bg-[#1c1e26] rounded-3xl p-10 w-full max-w-lg border border-[#252830] shadow-[0_0_50px_rgba(0,0,0,0.5)] animate-fade-in" onClick={e => e.stopPropagation()}>
            <h3 className="font-headline text-3xl font-bold mb-8 text-on-surface tracking-tight">{editCategoria?.id ? 'Editar' : 'Nova'} Categoria</h3>
            <div className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] uppercase tracking-widest font-bold text-on-surface-variant/60 ml-1">Nome da Categoria</label>
                <input value={editCategoria?.nome || ''} onChange={e => setEditCategoria(p => ({ ...p, nome: e.target.value }))} placeholder="Ex: Pizzas Gourmet" className="w-full bg-[#0c0e15] border-none focus:ring-1 focus:ring-primary-container rounded-xl py-4 px-5 text-sm text-on-surface" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] uppercase tracking-widest font-bold text-on-surface-variant/60 ml-1">Descrição</label>
                <textarea value={editCategoria?.descricao || ''} onChange={e => setEditCategoria(p => ({ ...p, descricao: e.target.value }))} placeholder="Pequena descrição para o cardápio" rows={3} className="w-full bg-[#0c0e15] border-none focus:ring-1 focus:ring-primary-container rounded-xl py-4 px-5 text-sm text-on-surface resize-none" />
              </div>
            </div>
            <div className="flex gap-4 mt-10">
              <button onClick={() => setShowCategoriaModal(false)} className="flex-1 py-4 rounded-xl border border-outline-variant/10 text-on-surface-variant font-headline font-bold text-xs uppercase tracking-widest hover:bg-surface-container-high transition-all">Cancelar</button>
              <button onClick={saveCategoria} className="flex-1 py-4 rounded-xl bg-primary-container text-on-primary-fixed font-headline font-bold text-xs uppercase tracking-widest hover:shadow-[0_0_20px_rgba(255,86,55,0.3)] transition-all">Salvar</button>
            </div>
          </div>
        </div>
      )}

      {showProdutoModal && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[999] flex items-center justify-center p-6" onClick={() => setShowProdutoModal(false)}>
          <div className="bg-[#1c1e26] rounded-3xl p-10 w-full max-w-2xl border border-[#252830] shadow-[0_0_50px_rgba(0,0,0,0.5)] max-h-[90vh] overflow-y-auto no-scrollbar animate-fade-in" onClick={e => e.stopPropagation()}>
            <h3 className="font-headline text-3xl font-bold mb-8 text-on-surface tracking-tight">{editProduto?.id ? 'Editar' : 'Novo'} Produto</h3>
            <div className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] uppercase tracking-widest font-bold text-on-surface-variant/60 ml-1">Nome do Produto</label>
                <input value={editProduto?.nome || ''} onChange={e => setEditProduto(p => ({ ...p, nome: e.target.value }))} placeholder="Ex: Pizza Calabresa Especial" className="w-full bg-[#0c0e15] border-none focus:ring-1 focus:ring-primary-container rounded-xl py-4 px-5 text-sm text-on-surface" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] uppercase tracking-widest font-bold text-on-surface-variant/60 ml-1">Descrição Detalhada</label>
                <textarea value={editProduto?.descricao || ''} onChange={e => setEditProduto(p => ({ ...p, descricao: e.target.value }))} placeholder="Descreva os ingredientes e detalhes" rows={3} className="w-full bg-[#0c0e15] border-none focus:ring-1 focus:ring-primary-container rounded-xl py-4 px-5 text-sm text-on-surface resize-none" />
              </div>

              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[10px] uppercase tracking-widest font-bold text-on-surface-variant/60 ml-1">Preço Base (R$)</label>
                  <input type="number" step="0.01" value={editProduto?.preco || ''} onChange={e => setEditProduto(p => ({ ...p, preco: Number(e.target.value) }))} className="w-full bg-[#0c0e15] border-none focus:ring-1 focus:ring-primary-container rounded-xl py-4 px-5 text-sm text-on-surface" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] uppercase tracking-widest font-bold text-on-surface-variant/60 ml-1">Tempo de Preparo (Min)</label>
                  <input type="number" value={editProduto?.tempo_preparo || 30} onChange={e => setEditProduto(p => ({ ...p, tempo_preparo: Number(e.target.value) }))} className="w-full bg-[#0c0e15] border-none focus:ring-1 focus:ring-primary-container rounded-xl py-4 px-5 text-sm text-on-surface" />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] uppercase tracking-widest font-bold text-on-surface-variant/60 ml-1">Categoria</label>
                <select value={editProduto?.categoria_id || ''} onChange={e => setEditProduto(p => ({ ...p, categoria_id: e.target.value }))} className="w-full bg-[#0c0e15] border-none focus:ring-1 focus:ring-primary-container rounded-xl py-4 px-5 text-sm text-on-surface cursor-pointer">
                  <option value="">Sem categoria</option>
                  {categorias.map(c => <option key={c.id} value={c.id}>{c.nome}</option>)}
                </select>
              </div>

              <div className="flex gap-8 pt-2">
                <label className="flex items-center gap-3 cursor-pointer group">
                  <div className={`w-5 h-5 rounded flex items-center justify-center border-2 transition-all ${editProduto?.disponivel !== false ? 'bg-primary-container border-primary-container' : 'border-outline-variant/30'}`}>
                    <input type="checkbox" className="hidden" checked={editProduto?.disponivel ?? true} onChange={e => setEditProduto(p => ({ ...p, disponivel: e.target.checked }))} />
                    {editProduto?.disponivel !== false && <span className="material-symbols-outlined text-white text-base">check</span>}
                  </div>
                  <span className="text-sm font-headline font-bold uppercase tracking-widest opacity-80 group-hover:opacity-100">Disponível</span>
                </label>
                <label className="flex items-center gap-3 cursor-pointer group">
                   <div className={`w-5 h-5 rounded flex items-center justify-center border-2 transition-all ${editProduto?.destaque ? 'bg-secondary border-secondary' : 'border-outline-variant/30'}`}>
                    <input type="checkbox" className="hidden" checked={editProduto?.destaque ?? false} onChange={e => setEditProduto(p => ({ ...p, destaque: e.target.checked }))} />
                    {editProduto?.destaque && <span className="material-symbols-outlined text-on-secondary text-base">star</span>}
                  </div>
                  <span className="text-sm font-headline font-bold uppercase tracking-widest opacity-80 group-hover:opacity-100 text-secondary">Destaque</span>
                </label>
              </div>

              {editProduto?.id && (
                <div className="border-t border-outline-variant/10 pt-8 mt-4">
                  <h4 className="text-xs font-headline font-bold uppercase tracking-[0.2em] mb-4 text-on-surface-variant">Preços por Tamanho (Variações)</h4>
                  <div className="space-y-3">
                    {precos.map(pt => (
                      <div key={pt.id} className="flex items-center justify-between bg-[#11131a] p-4 rounded-xl border border-outline-variant/5">
                        <span className="text-sm font-bold uppercase tracking-widest">{pt.tamanho} — <span className="text-[#4ade80]">R$ {Number(pt.preco).toFixed(2)}</span></span>
                        <button onClick={() => deletePreco(pt.id, editProduto.id!)} className="w-8 h-8 flex items-center justify-center bg-error/10 text-error rounded-lg hover:bg-error hover:text-white transition-all">
                          <span className="material-symbols-outlined text-sm">close</span>
                        </button>
                      </div>
                    ))}
                    <div className="flex gap-3 mt-4">
                      <input id="newTam" placeholder="Tamanho (Ex: G, M, 2L)" className="flex-1 bg-[#0c0e15] border-none focus:ring-1 focus:ring-primary-container rounded-xl py-3 px-4 text-xs text-on-surface" />
                      <input id="newPreco" type="number" step="0.01" placeholder="R$ 0,00" className="w-28 bg-[#0c0e15] border-none focus:ring-1 focus:ring-primary-container rounded-xl py-3 px-4 text-xs text-on-surface" />
                      <button onClick={() => {
                        const t = (document.getElementById('newTam') as HTMLInputElement).value
                        const p = Number((document.getElementById('newPreco') as HTMLInputElement).value)
                        if (t && p > 0) addPreco(editProduto.id!, t, p)
                      }} className="bg-secondary-container text-on-secondary-container px-4 rounded-xl text-xs font-bold uppercase">+</button>
                    </div>
                  </div>
                </div>
              )}
            </div>
            <div className="flex gap-4 mt-12">
              <button onClick={() => setShowProdutoModal(false)} className="flex-1 py-4 rounded-xl border border-outline-variant/10 text-on-surface-variant font-headline font-bold text-xs uppercase tracking-widest hover:bg-surface-container-high transition-all">Cancelar</button>
              <button onClick={saveProduto} className="flex-1 py-4 rounded-xl bg-primary-container text-on-primary-fixed font-headline font-bold text-xs uppercase tracking-widest hover:shadow-[0_0_20px_rgba(255,86,55,0.3)] transition-all">Salvar</button>
            </div>
          </div>
        </div>
      )}
    </>
  )
}

import { useCallback, useEffect, useState } from 'react'
import { supabase } from '../lib/supabase'

interface Categoria { id: string; nome: string }
interface Produto { id: string; categoria_id: string; nome: string; descricao: string; preco: number; disponivel: boolean; imagem_url: string }
interface CartItem { produto: Produto; quantidade: number }
interface EnderecoViaCep { logradouro: string; bairro: string; localidade: string; uf: string }

type Step = 'menu' | 'dados' | 'pagamento'

export default function CardapioOnlinePage() {
  const [categorias, setCategorias] = useState<Categoria[]>([])
  const [produtos, setProdutos] = useState<Produto[]>([])
  const [cart, setCart] = useState<CartItem[]>([])
  const [step, setStep] = useState<Step>('menu')
  const [filtroCategoria, setFiltroCategoria] = useState<string | null>(null)
  const [busca, setBusca] = useState('')
  const [loading, setLoading] = useState(false)
  const [sucesso, setSucesso] = useState(false)

  // Dados do cliente
  const [nome, setNome] = useState('')
  const [telefone, setTelefone] = useState('')
  const [cep, setCep] = useState('')
  const [endereco, setEndereco] = useState('')
  const [numero, setNumero] = useState('')
  const [complemento, setComplemento] = useState('')
  const [bairro, setBairro] = useState('')
  const [cidade, setCidade] = useState('')
  const [estado, setEstado] = useState('')
  const [formaPagamento, setFormaPagamento] = useState('pix')
  const [observacoes, setObservacoes] = useState('')

  const fetchData = useCallback(async () => {
    const [{ data: cats }, { data: prods }] = await Promise.all([
      supabase.from('categorias').select('*').eq('ativo', true).order('ordem'),
      supabase.from('produtos').select('*').eq('disponivel', true).order('ordem'),
    ])
    if (cats) setCategorias(cats)
    if (prods) setProdutos(prods)
  }, [])

  useEffect(() => { fetchData() }, [fetchData])

  const addToCart = (p: Produto) => {
    setCart(prev => {
      const existing = prev.find(item => item.produto.id === p.id)
      if (existing) return prev.map(item => item.produto.id === p.id ? { ...item, quantidade: item.quantidade + 1 } : item)
      return [...prev, { produto: p, quantidade: 1 }]
    })
  }

  const removeFromCart = (id: string) => {
    setCart(prev => prev.map(item => item.produto.id === id ? { ...item, quantidade: item.quantidade - 1 } : item).filter(item => item.quantidade > 0))
  }

  const subtotal = cart.reduce((sum, item) => sum + Number(item.produto.preco) * item.quantidade, 0)
  const taxaEntrega = 5
  const total = subtotal + taxaEntrega

  const buscarCep = async () => {
    if (cep.length < 8) return
    try {
      const res = await fetch(`https://viacep.com.br/ws/${cep.replace(/\D/g, '')}/json/`)
      const data: EnderecoViaCep = await res.json()
      if (data.logradouro) {
        setEndereco(data.logradouro)
        setBairro(data.bairro)
        setCidade(data.localidade)
        setEstado(data.uf)
      }
    } catch { /* ignore */ }
  }

  const finalizarPedido = async () => {
    if (!nome || !telefone || !cep) return
    setLoading(true)
    const itens = cart.map(item => ({
      produto_id: item.produto.id,
      produto_nome: item.produto.nome,
      quantidade: item.quantidade,
      preco_unitario: item.produto.preco,
      total: Number(item.produto.preco) * item.quantidade,
    }))

    await supabase.from('pedidos_online').insert({
      cliente_nome: nome,
      cliente_telefone: telefone,
      cep, endereco, numero_endereco: numero, complemento, bairro, cidade, estado,
      itens: JSON.stringify(itens),
      subtotal, taxa_entrega: taxaEntrega, total,
      forma_pagamento: formaPagamento,
      observacoes,
    })

    setLoading(false)
    setSucesso(true)
    setCart([])
  }

  const filteredProdutos = produtos.filter(p => {
    if (filtroCategoria && p.categoria_id !== filtroCategoria) return false
    if (busca && !p.nome.toLowerCase().includes(busca.toLowerCase())) return false
    return true
  })

  if (sucesso) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center p-6">
        <div className="text-center animate-fade-in">
          <span className="material-symbols-outlined text-green-400 text-6xl mb-4 block">check_circle</span>
          <h2 className="text-3xl font-[Outfit] font-bold text-on-surface mb-2">Pedido Enviado!</h2>
          <p className="text-on-surface-variant">Seu pedido foi recebido e está sendo preparado.</p>
          <button onClick={() => { setSucesso(false); setStep('menu') }} className="mt-6 bg-primary-container text-on-primary-fixed px-8 py-3 rounded-xl font-bold">Novo Pedido</button>
        </div>
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-background">
      {/* Header */}
      <header className="sticky top-0 z-50 bg-background/80 backdrop-blur-md border-b border-outline-variant/10 px-6 py-4">
        <div className="max-w-5xl mx-auto flex justify-between items-center">
          <h1 className="text-2xl font-black italic text-primary-container font-[Outfit]">KERO</h1>
          <button onClick={() => setStep(step === 'menu' ? 'dados' : 'menu')} className="relative bg-primary-container text-on-primary-fixed px-5 py-2 rounded-xl font-bold text-sm flex items-center gap-2">
            <span className="material-symbols-outlined text-lg">shopping_cart</span>
            {cart.length > 0 && <span className="bg-on-primary-fixed text-primary-container w-5 h-5 rounded-full text-xs flex items-center justify-center font-bold">{cart.reduce((s, i) => s + i.quantidade, 0)}</span>}
          </button>
        </div>
      </header>

      <div className="max-w-5xl mx-auto px-6 py-8">
        {/* Stepper */}
        {step !== 'menu' && (
          <div className="flex items-center gap-4 mb-8">
            {['Carrinho', 'Dados', 'Pagamento'].map((s, i) => {
              const stepMap: Step[] = ['menu', 'dados', 'pagamento']
              const active = stepMap.indexOf(step) >= i
              return (
                <div key={s} className="flex items-center gap-2">
                  <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold ${active ? 'bg-primary-container text-on-primary-fixed' : 'bg-surface-container-high text-on-surface-variant'}`}>{i + 1}</div>
                  <span className={`text-sm font-bold ${active ? 'text-on-surface' : 'text-on-surface-variant/50'}`}>{s}</span>
                  {i < 2 && <div className={`w-8 h-[2px] ${active ? 'bg-primary-container' : 'bg-surface-container-high'}`} />}
                </div>
              )
            })}
          </div>
        )}

        {/* Step 1: Menu */}
        {step === 'menu' && (
          <div className="animate-fade-in">
            <input value={busca} onChange={e => setBusca(e.target.value)} placeholder="Buscar no cardápio..." className="w-full bg-surface-container border border-outline-variant/10 rounded-xl py-3 px-5 text-sm text-on-surface mb-6 placeholder:text-on-surface-variant/40" />
            <div className="flex gap-2 overflow-x-auto pb-4 mb-6">
              <button onClick={() => setFiltroCategoria(null)} className={`px-4 py-2 rounded-full text-xs font-bold whitespace-nowrap transition-all ${!filtroCategoria ? 'bg-primary-container text-on-primary-fixed' : 'bg-surface-container-high text-on-surface-variant'}`}>Tudo</button>
              {categorias.map(c => (
                <button key={c.id} onClick={() => setFiltroCategoria(c.id)} className={`px-4 py-2 rounded-full text-xs font-bold whitespace-nowrap transition-all ${filtroCategoria === c.id ? 'bg-primary-container text-on-primary-fixed' : 'bg-surface-container-high text-on-surface-variant'}`}>{c.nome}</button>
              ))}
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {filteredProdutos.map(p => {
                const inCart = cart.find(i => i.produto.id === p.id)
                return (
                  <div key={p.id} className="bg-surface-container p-5 rounded-xl border border-outline-variant/10 flex gap-4 hover:border-primary-container/20 transition-all">
                    <div className="flex-1">
                      <h4 className="font-[Outfit] font-bold">{p.nome}</h4>
                      <p className="text-xs text-on-surface-variant mt-1 line-clamp-2">{p.descricao}</p>
                      <p className="text-lg font-[Outfit] font-bold text-primary mt-2">{Number(p.preco).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}</p>
                    </div>
                    <div className="flex flex-col items-center justify-end gap-2">
                      {inCart ? (
                        <div className="flex items-center gap-2">
                          <button onClick={() => removeFromCart(p.id)} className="w-8 h-8 rounded-lg bg-surface-container-high flex items-center justify-center text-on-surface hover:bg-error/20 transition-all"><span className="material-symbols-outlined text-sm">remove</span></button>
                          <span className="text-sm font-bold w-6 text-center">{inCart.quantidade}</span>
                          <button onClick={() => addToCart(p)} className="w-8 h-8 rounded-lg bg-primary-container flex items-center justify-center text-on-primary-fixed"><span className="material-symbols-outlined text-sm">add</span></button>
                        </div>
                      ) : (
                        <button onClick={() => addToCart(p)} className="bg-primary-container text-on-primary-fixed px-4 py-2 rounded-lg text-xs font-bold">Adicionar</button>
                      )}
                    </div>
                  </div>
                )
              })}
            </div>
            {cart.length > 0 && (
              <div className="sticky bottom-4 mt-8">
                <button onClick={() => setStep('dados')} className="w-full bg-primary-container text-on-primary-fixed py-4 rounded-xl font-bold text-sm flex items-center justify-center gap-3 shadow-[0_0_40px_-10px_rgba(255,86,55,0.4)]">
                  Ver Carrinho ({cart.reduce((s, i) => s + i.quantidade, 0)} itens) — {total.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                  <span className="material-symbols-outlined">arrow_forward</span>
                </button>
              </div>
            )}
          </div>
        )}

        {/* Step 2: Dados do cliente */}
        {step === 'dados' && (
          <div className="animate-fade-in max-w-lg mx-auto">
            <h3 className="font-[Outfit] text-2xl font-bold mb-6">Seus Dados</h3>
            <div className="space-y-4">
              <input value={nome} onChange={e => setNome(e.target.value)} placeholder="Nome completo" className="w-full bg-surface-container-lowest border border-outline-variant/10 rounded-xl py-3 px-4 text-sm text-on-surface" required />
              <input value={telefone} onChange={e => setTelefone(e.target.value)} placeholder="WhatsApp (11) 99999-9999" className="w-full bg-surface-container-lowest border border-outline-variant/10 rounded-xl py-3 px-4 text-sm text-on-surface" required />
              <div className="flex gap-3">
                <input value={cep} onChange={e => setCep(e.target.value)} onBlur={buscarCep} placeholder="CEP" className="w-40 bg-surface-container-lowest border border-outline-variant/10 rounded-xl py-3 px-4 text-sm text-on-surface" required />
                <button onClick={buscarCep} className="bg-surface-container-high px-4 rounded-xl text-xs font-bold text-on-surface-variant">Buscar</button>
              </div>
              <input value={endereco} onChange={e => setEndereco(e.target.value)} placeholder="Rua" className="w-full bg-surface-container-lowest border border-outline-variant/10 rounded-xl py-3 px-4 text-sm text-on-surface" />
              <div className="grid grid-cols-2 gap-3">
                <input value={numero} onChange={e => setNumero(e.target.value)} placeholder="Número" className="w-full bg-surface-container-lowest border border-outline-variant/10 rounded-xl py-3 px-4 text-sm text-on-surface" />
                <input value={complemento} onChange={e => setComplemento(e.target.value)} placeholder="Complemento" className="w-full bg-surface-container-lowest border border-outline-variant/10 rounded-xl py-3 px-4 text-sm text-on-surface" />
              </div>
              <input value={bairro} onChange={e => setBairro(e.target.value)} placeholder="Bairro" className="w-full bg-surface-container-lowest border border-outline-variant/10 rounded-xl py-3 px-4 text-sm text-on-surface" />
              <div className="grid grid-cols-2 gap-3">
                <input value={cidade} onChange={e => setCidade(e.target.value)} placeholder="Cidade" className="w-full bg-surface-container-lowest border border-outline-variant/10 rounded-xl py-3 px-4 text-sm text-on-surface" />
                <input value={estado} onChange={e => setEstado(e.target.value)} placeholder="UF" className="w-full bg-surface-container-lowest border border-outline-variant/10 rounded-xl py-3 px-4 text-sm text-on-surface" />
              </div>
              <textarea value={observacoes} onChange={e => setObservacoes(e.target.value)} placeholder="Observações do pedido" rows={3} className="w-full bg-surface-container-lowest border border-outline-variant/10 rounded-xl py-3 px-4 text-sm text-on-surface resize-none" />
            </div>
            <div className="flex gap-3 mt-6">
              <button onClick={() => setStep('menu')} className="flex-1 py-3 rounded-xl border border-outline-variant/20 text-on-surface-variant font-bold text-sm">Voltar</button>
              <button onClick={() => setStep('pagamento')} disabled={!nome || !telefone || !cep} className="flex-1 py-3 rounded-xl bg-primary-container text-on-primary-fixed font-bold text-sm disabled:opacity-50">Continuar</button>
            </div>
          </div>
        )}

        {/* Step 3: Pagamento */}
        {step === 'pagamento' && (
          <div className="animate-fade-in max-w-lg mx-auto">
            <h3 className="font-[Outfit] text-2xl font-bold mb-6">Forma de Pagamento</h3>
            {/* Resumo do pedido */}
            <div className="bg-surface-container rounded-xl p-6 mb-6 border border-outline-variant/10">
              {cart.map(item => (
                <div key={item.produto.id} className="flex justify-between py-2 border-b border-outline-variant/5 last:border-0">
                  <span className="text-sm">{item.quantidade}x {item.produto.nome}</span>
                  <span className="text-sm font-bold">{(Number(item.produto.preco) * item.quantidade).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}</span>
                </div>
              ))}
              <div className="flex justify-between pt-3 mt-3 border-t border-outline-variant/10">
                <span className="text-xs text-on-surface-variant">Subtotal</span>
                <span className="text-sm">{subtotal.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}</span>
              </div>
              <div className="flex justify-between">
                <span className="text-xs text-on-surface-variant">Entrega</span>
                <span className="text-sm">{taxaEntrega.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}</span>
              </div>
              <div className="flex justify-between pt-3 mt-3 border-t border-outline-variant/10">
                <span className="font-bold">Total</span>
                <span className="text-xl font-[Outfit] font-bold text-primary">{total.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}</span>
              </div>
            </div>

            <div className="space-y-3 mb-6">
              {[
                { value: 'pix', label: 'PIX', icon: 'qr_code' },
                { value: 'cartao', label: 'Cartão', icon: 'credit_card' },
                { value: 'dinheiro', label: 'Dinheiro', icon: 'payments' },
              ].map(opt => (
                <button key={opt.value} onClick={() => setFormaPagamento(opt.value)} className={`w-full p-4 rounded-xl border flex items-center gap-3 transition-all ${formaPagamento === opt.value ? 'border-primary-container bg-primary-container/10' : 'border-outline-variant/10 hover:border-outline-variant/30'}`}>
                  <span className="material-symbols-outlined">{opt.icon}</span>
                  <span className="font-bold text-sm">{opt.label}</span>
                </button>
              ))}
            </div>

            <div className="flex gap-3">
              <button onClick={() => setStep('dados')} className="flex-1 py-3 rounded-xl border border-outline-variant/20 text-on-surface-variant font-bold text-sm">Voltar</button>
              <button onClick={finalizarPedido} disabled={loading} className="flex-1 py-4 rounded-xl bg-primary-container text-on-primary-fixed font-bold text-sm disabled:opacity-50 flex items-center justify-center gap-2">
                {loading ? <div className="w-5 h-5 border-2 border-on-primary-fixed border-t-transparent rounded-full animate-spin" /> : 'Finalizar Pedido'}
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  )
}

import { useCallback, useEffect, useState } from 'react'
import { supabase } from '../lib/supabase'
import { useRealtime } from '../hooks/useRealtime'

interface KPIs {
  faturamento: number
  totalPedidos: number
  ticketMedio: number
  tempoEntrega: number
  visualizacoes: number
  avaliacao: number
  pedidosAbertos: number
  totalEntregues: number
}

interface KpiData {
  id: string;
  icon: string;
  label: string;
  value: string | number;
  colorClass?: string;
  isCurrency?: boolean;
}

function KpiCard({ 
  data, 
  index, 
  onDragStart, 
  onDrop, 
  isDragging 
}: {
  data: KpiData; 
  index: number;
  onDragStart: (id: string) => void;
  onDrop: (targetId: string) => void;
  isDragging: boolean;
}) {
  const valueDisplay = data.isCurrency 
    ? data.value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })
    : String(data.value);

  return (
    <div 
      draggable
      onDragStart={() => onDragStart(data.id)}
      onDragOver={(e) => e.preventDefault()}
      onDrop={() => onDrop(data.id)}
      style={{ animationDelay: `${index * 100}ms` }}
      className={`bg-[#16181f] p-6 rounded-3xl border transition-all duration-300 group cursor-grab active:cursor-grabbing shadow-xl animate-fade-in fill-mode-both ${
        isDragging ? 'border-primary-container opacity-40 scale-95 shadow-none' : 'border-[#252830] hover:border-primary-container/30 hover:shadow-primary-container/5'
      }`}
    >
      <div className="flex justify-between items-start mb-6">
        <div className="flex flex-col">
          <span className="text-[10px] font-headline font-bold text-on-surface-variant/40 tracking-[0.2em] uppercase mb-1">{data.label}</span>
          <div className="h-1 w-6 bg-primary-container/20 rounded-full group-hover:w-full transition-all duration-500" />
        </div>
        <div className={`w-10 h-10 rounded-2xl bg-surface-container-high flex items-center justify-center ${data.colorClass} opacity-80 group-hover:opacity-100 group-hover:scale-110 transition-all`}>
          <span className="material-symbols-outlined text-xl">{data.icon}</span>
        </div>
      </div>
      <h3 className={`text-2xl font-headline font-bold tracking-tight ${data.colorClass || 'text-on-surface'}`}>
        {valueDisplay}
      </h3>
    </div>
  )
}

export default function DashboardPage() {
  const [kpis, setKpis] = useState<KPIs>({
    faturamento: 0, totalPedidos: 0, ticketMedio: 0, tempoEntrega: 0,
    visualizacoes: 0, avaliacao: 0, pedidosAbertos: 0, totalEntregues: 0,
  })

  const [order, setOrder] = useState<string[]>([
    'faturamento', 'totalPedidos', 'ticketMedio', 'pedidosAbertos',
    'totalEntregues', 'tempoEntrega', 'avaliacao', 'visualizacoes'
  ])

  const [draggedKpi, setDraggedKpi] = useState<string | null>(null)

  const fetchKpis = useCallback(async () => {
    const today = new Date().toISOString().split('T')[0]
    const { data: pedidosHoje } = await supabase.from('pedidos').select('*').gte('created_at', today)
    const { data: pedidosOnlineHoje } = await supabase.from('pedidos_online').select('*').gte('created_at', today)

    const allPedidos = [...(pedidosHoje || []), ...(pedidosOnlineHoje || [])]
    const entregues = allPedidos.filter(p => p.status === 'entregue')
    const abertos = allPedidos.filter(p => !['entregue', 'cancelado'].includes(p.status))
    const faturamento = entregues.reduce((sum, p) => sum + Number(p.total || 0), 0)

    setKpis({
      faturamento,
      totalPedidos: allPedidos.length,
      ticketMedio: entregues.length > 0 ? faturamento / entregues.length : 0,
      tempoEntrega: 38,
      visualizacoes: (pedidosOnlineHoje?.length || 0) * 42,
      avaliacao: 4.9,
      pedidosAbertos: abertos.length,
      totalEntregues: entregues.length,
    })
  }, [])

  useEffect(() => { fetchKpis() }, [fetchKpis])
  useRealtime('pedidos', fetchKpis)
  useRealtime('pedidos_online', fetchKpis)

  const handleDropKpi = (targetId: string) => {
    if (!draggedKpi || draggedKpi === targetId) return
    const newOrder = [...order]
    const dIdx = newOrder.indexOf(draggedKpi)
    const tIdx = newOrder.indexOf(targetId)
    newOrder.splice(dIdx, 1)
    newOrder.splice(tIdx, 0, draggedKpi)
    setOrder(newOrder)
    setDraggedKpi(null)
  }

  const [chartsOrder, setChartsOrder] = useState<string[]>(['receita', 'picos', 'funil'])
  const [draggedChart, setDraggedChart] = useState<string | null>(null)

  const handleDropCharts = (targetId: string) => {
    if (!draggedChart || draggedChart === targetId) return
    const newOrder = [...chartsOrder]
    const dIdx = newOrder.indexOf(draggedChart)
    const tIdx = newOrder.indexOf(targetId)
    newOrder.splice(dIdx, 1)
    newOrder.splice(tIdx, 0, draggedChart)
    setChartsOrder(newOrder)
    setDraggedChart(null)
  }

  const kpiMap: Record<string, KpiData> = {
    faturamento: { id: 'faturamento', icon: 'payments', label: 'Faturamento', value: kpis.faturamento, isCurrency: true, colorClass: 'text-[#4ade80]' },
    totalPedidos: { id: 'totalPedidos', icon: 'local_mall', label: 'Pedidos Total', value: kpis.totalPedidos, colorClass: 'text-primary' },
    ticketMedio: { id: 'ticketMedio', icon: 'analytics', label: 'Ticket Médio', value: kpis.ticketMedio, isCurrency: true, colorClass: 'text-secondary' },
    pedidosAbertos: { id: 'pedidosAbertos', icon: 'pending_actions', label: 'Em Preparo', value: kpis.pedidosAbertos, colorClass: 'text-orange-400' },
    totalEntregues: { id: 'totalEntregues', icon: 'task_alt', label: 'Entregues', value: kpis.totalEntregues, colorClass: 'text-[#4ade80]' },
    tempoEntrega: { id: 'tempoEntrega', icon: 'schedule', label: 'Tempo Médio', value: `${kpis.tempoEntrega} min`, colorClass: 'text-secondary' },
    avaliacao: { id: 'avaliacao', icon: 'grade', label: 'Avaliação NPS', value: kpis.avaliacao.toFixed(1), colorClass: 'text-yellow-400' },
    visualizacoes: { id: 'visualizacoes', icon: 'visibility', label: 'Visitas Cardápio', value: kpis.visualizacoes, colorClass: 'text-primary' },
  }

  const renderChart = (id: string) => {
    const commonClass = `bg-[#16181f] p-8 rounded-3xl border transition-all duration-500 shadow-2xl animate-fade-in relative group cursor-grab active:cursor-grabbing ${draggedChart === id ? 'opacity-20 border-primary-container scale-95' : 'border-[#252830] hover:border-primary-container/20'}`
    const dragProps = {
      draggable: true,
      onDragStart: () => setDraggedChart(id),
      onDragOver: (e: any) => e.preventDefault(),
      onDrop: () => handleDropCharts(id)
    }

    if (id === 'receita') {
      return (
        <div key="receita" {...dragProps} className={commonClass} style={{ animationDelay: '400ms' }}>
          <div className="flex justify-between items-start mb-10">
            <div>
              <h3 className="text-xl font-headline font-bold text-on-surface">Receita Mensal</h3>
              <p className="text-[10px] text-on-surface-variant/40 font-body uppercase tracking-[0.2em] mt-1">Volume de vendas / 7 dias</p>
            </div>
            <span className="material-symbols-outlined text-primary-container opacity-20 text-2xl">bar_chart</span>
          </div>
