import { useCallback, useEffect, useState } from 'react'
import { supabase } from '../lib/supabase'
import { useRealtime } from '../hooks/useRealtime'

interface Produto { id: string; nome: string; preco: number; categoria_id: string }
interface Categoria { id: string; nome: string }
interface ItemPedido { produto: Produto; quantidade: number; observacoes: string }

export default function PdvPage() {
  const [produtos, setProdutos] = useState<Produto[]>([])
  const [categorias, setCategorias] = useState<Categoria[]>([])
  const [itens, setItens] = useState<ItemPedido[]>([])
  const [filtro, setFiltro] = useState<string | null>(null)
  const [busca, setBusca] = useState('')
  const [tipo, setTipo] = useState<'balcao' | 'entrega' | 'mesa'>('balcao')
  const [clienteNome, setClienteNome] = useState('')
  const [clienteTelefone, setClienteTelefone] = useState('')
  const [mesaNumero, setMesaNumero] = useState('')
  const [observacoes, setObservacoes] = useState('')
  const [formaPagamento, setFormaPagamento] = useState('dinheiro')
  const [desconto, setDesconto] = useState(0)
  const [salvando, setSalvando] = useState(false)
  const [sucesso, setSucesso] = useState(false)

  const fetchData = useCallback(async () => {
    const [{ data: prods }, { data: cats }] = await Promise.all([
      supabase.from('produtos').select('*').eq('disponivel', true).order('ordem'),
      supabase.from('categorias').select('*').order('ordem'),
    ])
    if (prods) setProdutos(prods)
    if (cats) setCategorias(cats)
  }, [])

  useEffect(() => { fetchData() }, [fetchData])
  useRealtime('produtos', fetchData)

  const addItem = (p: Produto) => {
    setItens(prev => {
      const existing = prev.find(i => i.produto.id === p.id)
      if (existing) return prev.map(i => i.produto.id === p.id ? { ...i, quantidade: i.quantidade + 1 } : i)
      return [...prev, { produto: p, quantidade: 1, observacoes: '' }]
    })
  }

  const removeItem = (id: string) => {
    setItens(prev => prev.map(i => i.produto.id === id ? { ...i, quantidade: i.quantidade - 1 } : i).filter(i => i.quantidade > 0))
  }

  const subtotal = itens.reduce((sum, i) => sum + Number(i.produto.preco) * i.quantidade, 0)
  const total = subtotal - desconto

  const salvarPedido = async () => {
    if (itens.length === 0) return
    setSalvando(true)

    const { data: pedido } = await supabase.from('pedidos').insert({
      cliente_nome: clienteNome || null,
      cliente_telefone: clienteTelefone || null,
      tipo,
      mesa_numero: tipo === 'mesa' ? Number(mesaNumero) || null : null,
      subtotal,
      desconto,
      total,
      forma_pagamento: formaPagamento,
      observacoes: observacoes || null,
    }).select().single()

    if (pedido) {
      const itensInsert = itens.map(i => ({
        pedido_id: pedido.id,
        produto_id: i.produto.id,
        produto_nome: i.produto.nome,
        quantidade: i.quantidade,
        preco_unitario: i.produto.preco,
        total: Number(i.produto.preco) * i.quantidade,
        observacoes: i.observacoes || null,
      }))
      await supabase.from('itens_pedido').insert(itensInsert)
    }

    setSalvando(false)
    setSucesso(true)
    setTimeout(() => {
      setSucesso(false)
      setItens([])
      setClienteNome('')
      setClienteTelefone('')
      setMesaNumero('')
      setObservacoes('')
      setDesconto(0)
    }, 2000)
  }

  const filteredProdutos = produtos.filter(p => {
    if (filtro && p.categoria_id !== filtro) return false
    if (busca && !p.nome.toLowerCase().includes(busca.toLowerCase())) return false
    return true
  })

  return (
    <div className="animate-fade-in flex gap-6 h-[calc(100vh-8rem)]">
      {/* Left - Product Grid */}
      <div className="flex-1 flex flex-col min-w-0">
        <div className="mb-4 flex items-end justify-between">
          <div>
            <span className="text-secondary font-bold uppercase tracking-[0.3em] text-[10px] mb-1 block">Ponto de Venda</span>
            <h2 className="text-4xl font-[Outfit] font-bold text-on-background tracking-tighter">PDV</h2>
          </div>
        </div>

        <input value={busca} onChange={e => setBusca(e.target.value)} placeholder="Buscar produto..." className="w-full bg-surface-container border border-outline-variant/10 rounded-xl py-3 px-5 text-sm text-on-surface mb-4 placeholder:text-on-surface-variant/40" />

        <div className="flex gap-2 overflow-x-auto pb-3 mb-4">
          <button onClick={() => setFiltro(null)} className={`px-3 py-1.5 rounded-full text-xs font-bold whitespace-nowrap ${!filtro ? 'bg-primary-container text-on-primary-fixed' : 'bg-surface-container-high text-on-surface-variant'}`}>Todos</button>
          {categorias.map(c => (
            <button key={c.id} onClick={() => setFiltro(c.id)} className={`px-3 py-1.5 rounded-full text-xs font-bold whitespace-nowrap ${filtro === c.id ? 'bg-primary-container text-on-primary-fixed' : 'bg-surface-container-high text-on-surface-variant'}`}>{c.nome}</button>
          ))}
        </div>

        <div className="grid grid-cols-2 lg:grid-cols-3 gap-3 overflow-y-auto flex-1">
          {filteredProdutos.map(p => (
            <button key={p.id} onClick={() => addItem(p)} className="bg-surface-container p-4 rounded-xl border border-outline-variant/10 hover:border-primary-container/30 hover:scale-[1.02] transition-all text-left">
              <h4 className="font-[Outfit] font-bold text-sm truncate">{p.nome}</h4>
              <p className="text-sm font-bold text-primary mt-1">{Number(p.preco).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}</p>
            </button>
          ))}
        </div>
      </div>

      {/* Right - Cart / Order */}
      <div className="w-96 bg-surface-container rounded-2xl border border-outline-variant/10 flex flex-col">
        <div className="p-6 border-b border-outline-variant/10">
          <h3 className="font-[Outfit] font-bold text-lg mb-4">Pedido Atual</h3>
          <div className="flex gap-2">
            {(['balcao', 'entrega', 'mesa'] as const).map(t => (
              <button key={t} onClick={() => setTipo(t)} className={`flex-1 py-2 rounded-lg text-xs font-bold uppercase transition-all ${tipo === t ? 'bg-primary-container text-on-primary-fixed' : 'bg-surface-container-high text-on-surface-variant'}`}>{t}</button>
            ))}
          </div>
          {tipo === 'mesa' && (
            <input value={mesaNumero} onChange={e => setMesaNumero(e.target.value)} placeholder="Nº Mesa" className="w-full bg-surface-container-lowest border border-outline-variant/10 rounded-lg py-2 px-3 text-sm text-on-surface mt-3" />
          )}
          <input value={clienteNome} onChange={e => setClienteNome(e.target.value)} placeholder="Nome do cliente" className="w-full bg-surface-container-lowest border border-outline-variant/10 rounded-lg py-2 px-3 text-sm text-on-surface mt-3" />
        </div>

        {/* Items */}
        <div className="flex-1 overflow-y-auto p-4 space-y-2">
          {itens.length === 0 ? (
            <div className="text-center text-on-surface-variant/40 py-12">
              <span className="material-symbols-outlined text-4xl mb-2 block">shopping_cart</span>
              <p className="text-sm">Adicione produtos ao pedido</p>
            </div>
          ) : itens.map(item => (
            <div key={item.produto.id} className="flex items-center gap-3 bg-surface-container-low p-3 rounded-lg">
              <div className="flex-1 min-w-0">
                <p className="text-sm font-bold truncate">{item.produto.nome}</p>
                <p className="text-xs text-on-surface-variant">{Number(item.produto.preco).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}</p>
              </div>
              <div className="flex items-center gap-2">
                <button onClick={() => removeItem(item.produto.id)} className="w-7 h-7 rounded bg-surface-container-high flex items-center justify-center"><span className="material-symbols-outlined text-sm">remove</span></button>
                <span className="text-sm font-bold w-5 text-center">{item.quantidade}</span>
                <button onClick={() => addItem(item.produto)} className="w-7 h-7 rounded bg-primary-container flex items-center justify-center text-on-primary-fixed"><span className="material-symbols-outlined text-sm">add</span></button>
              </div>
              <span className="text-sm font-bold w-20 text-right">{(Number(item.produto.preco) * item.quantidade).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}</span>
            </div>
          ))}
        </div>

        {/* Footer */}
        <div className="p-6 border-t border-outline-variant/10 space-y-3">
          <select value={formaPagamento} onChange={e => setFormaPagamento(e.target.value)} className="w-full bg-surface-container-lowest border border-outline-variant/10 rounded-lg py-2 px-3 text-sm text-on-surface">
            <option value="dinheiro">Dinheiro</option>
            <option value="pix">PIX</option>
            <option value="cartao_credito">Cartão Crédito</option>
            <option value="cartao_debito">Cartão Débito</option>
          </select>
          <div className="flex justify-between text-sm">
            <span className="text-on-surface-variant">Subtotal</span>
            <span>{subtotal.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}</span>
          </div>
          <div className="flex justify-between items-center text-sm">
            <span className="text-on-surface-variant">Desconto</span>
            <input type="number" value={desconto || ''} onChange={e => setDesconto(Number(e.target.value))} className="w-24 text-right bg-transparent border-b border-outline-variant/20 text-sm py-0 text-on-surface" />
          </div>
          <div className="flex justify-between pt-2 border-t border-outline-variant/10">
            <span className="font-bold text-lg">Total</span>
            <span className="text-2xl font-[Outfit] font-bold text-primary">{total.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}</span>
          </div>
          <button onClick={salvarPedido} disabled={itens.length === 0 || salvando} className={`w-full py-4 rounded-xl font-bold text-sm flex items-center justify-center gap-2 transition-all ${sucesso ? 'bg-green-500 text-white' : 'bg-primary-container text-on-primary-fixed'} disabled:opacity-50`}>
            {salvando ? <div className="w-5 h-5 border-2 border-on-primary-fixed border-t-transparent rounded-full animate-spin" /> : sucesso ? '✓ Pedido Salvo!' : 'Finalizar Pedido'}
          </button>
        </div>
      </div>
    </div>
  )
}

import { useState, useEffect, useCallback, useMemo } from 'react'
import { supabase } from '../lib/supabase'
import { useRealtime } from '../hooks/useRealtime'
import type { Pedido, PedidoOnline } from '../types/database'
import { format, differenceInMinutes, parseISO } from 'date-fns'
import { ptBR } from 'date-fns/locale/pt-BR'
const playAlertSound = () => {
  const audio = new Audio('/notification.mp3')
  audio.play().catch(console.error)
}

type UnifiedPedido = {
  id: string
  numero: number
  cliente_nome: string
  cliente_telefone: string
  total: number
  tipo_tabela: 'pedidos' | 'pedidos_online'
  raw_status: string
  status_kanban: 'novo' | 'em_preparo' | 'saiu_entrega' | 'entregue' | 'cancelado'
  created_at: string
  canal: 'balcao' | 'entrega' | 'mesa' | 'app' | 'telefone' | 'ifood' | 'rappi'
  forma_pagamento: string
  itens: any[] // Mapeados simplificados
  endereco_entrega?: string
}

const mapKanbanStatus = (rawStatus: string): UnifiedPedido['status_kanban'] => {
  if (['aberto', 'pendente', 'confirmado'].includes(rawStatus)) return 'novo'
  if (rawStatus === 'preparando') return 'em_preparo'
  if (['pronto', 'saiu_entrega'].includes(rawStatus)) return 'saiu_entrega'
  if (rawStatus === 'entregue') return 'entregue'
  return 'cancelado'
}

const COLUMNS = [
  { id: 'novo', title: 'Novo', color: 'border-blue-500', headerBg: 'bg-blue-500/10', textColor: 'text-blue-500' },
  { id: 'em_preparo', title: 'Em Preparo', color: 'border-orange-500', headerBg: 'bg-orange-500/10', textColor: 'text-orange-500' },
  { id: 'saiu_entrega', title: 'Saiu para Entrega', color: 'border-purple-500', headerBg: 'bg-purple-500/10', textColor: 'text-purple-500' },
  { id: 'entregue', title: 'Entregue', color: 'border-green-500', headerBg: 'bg-green-500/10', textColor: 'text-green-500' },
  { id: 'cancelado', title: 'Cancelado', color: 'border-red-500', headerBg: 'bg-red-500/10', textColor: 'text-red-500' },
] as const

export default function PedidosPage() {
  const [pedidos, setPedidos] = useState<UnifiedPedido[]>([])
  const [loading, setLoading] = useState(true)
  const [currentTime, setCurrentTime] = useState(new Date())

  // Drawer / Modal states
  const [selectedPedido, setSelectedPedido] = useState<UnifiedPedido | null>(null)
  const [cancelModalPedido, setCancelModalPedido] = useState<UnifiedPedido | null>(null)
  const [cancelReason, setCancelReason] = useState('')

  // Configuração de timer global 1min para cards
  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 60000)
    return () => clearInterval(timer)
  }, [])

  const fetchPedidos = useCallback(async () => {
    try {
      const today = new Date()
      // Pegar pelo menos os ultimos 2 dias pra garantir visualização (se passar da meia noite)
      today.setDate(today.getDate() - 1) 
      const isoToday = today.toISOString().split('T')[0]

      const { data: pdvList } = await supabase.from('pedidos').select('*, itens_pedido(*)').gte('created_at', isoToday)
      const { data: onlineList } = await supabase.from('pedidos_online').select('*').gte('created_at', isoToday)

      const unified: UnifiedPedido[] = []

      // PDV Mapping
      ;(pdvList || []).forEach((p: any) => {
        unified.push({
          id: p.id,
          numero: p.numero,
          cliente_nome: p.cliente_nome || 'Cliente Balcão',
          cliente_telefone: p.cliente_telefone || '',
          total: Number(p.total),
          tipo_tabela: 'pedidos',
          raw_status: p.status,
          status_kanban: mapKanbanStatus(p.status),
          created_at: p.created_at,
          canal: p.tipo,
          forma_pagamento: p.forma_pagamento,
          endereco_entrega: p.endereco_entrega,
          itens: p.itens_pedido?.map((ip: any) => ({
            nome: ip.produto_nome,
            qtd: ip.quantidade,
            variacao: ip.tamanho,
            obs: ip.observacoes
          })) || []
        })
      })

      // Online Mapping
      ;(onlineList || []).forEach((p: any) => {
        unified.push({
          id: p.id,
          numero: p.numero,
          cliente_nome: p.cliente_nome,
          cliente_telefone: p.cliente_telefone,
          total: Number(p.total),
          tipo_tabela: 'pedidos_online',
          raw_status: p.status,
          status_kanban: mapKanbanStatus(p.status),
          created_at: p.created_at,
          canal: 'app',
          forma_pagamento: p.forma_pagamento,
          endereco_entrega: `${p.endereco}, ${p.numero_endereco} - ${p.bairro}`,
          itens: Array.isArray(p.itens) ? p.itens.map((ip: any) => ({
             nome: ip.produto_nome,
             qtd: ip.quantidade,
             obs: ip.observacoes
          })) : []
        })
      })

      // Ordenar por data mais recente
      unified.sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime())

      setPedidos(unified)
    } catch (err) {
      console.error('Erro ao buscar pedidos', err)
    } finally {
      setLoading(false)
    }
  }, [])

  useEffect(() => {
    fetchPedidos()
  }, [fetchPedidos])

  // Callbacks para realtime
  useRealtime('pedidos', () => {
    playAlertSound()
    fetchPedidos()
  })
  useRealtime('pedidos_online', () => {
    playAlertSound()
    fetchPedidos()
  })

  // Handlers baseados na arquitetura da Fase 2
  const handleAvançarStatus = async (pedido: UnifiedPedido) => {
    const nextStatusMap: Record<string, string> = {
      aberto: 'preparando',
      pendente: 'preparando',
      confirmado: 'preparando',
      preparando: pedido.tipo_tabela === 'pedidos_online' ? 'saiu_entrega' : 'pronto',
      pronto: 'entregue',
      saiu_entrega: 'entregue'
    }

    const nextRaw = nextStatusMap[pedido.raw_status]
    if (!nextRaw) return

    try {
      const { error } = await supabase.from(pedido.tipo_tabela).update({ status: nextRaw }).eq('id', pedido.id)
      if (!error) {
        // Inserir histórico status silent failure
        await supabase.from('historico_status').insert({
          pedido_id: pedido.id,
          origem_tabela: pedido.tipo_tabela,
          status_anterior: pedido.raw_status,
          status_novo: nextRaw
        })
        fetchPedidos()

        // Atualiza a gaveta aberta, se houver
        if (selectedPedido && selectedPedido.id === pedido.id) {
           setSelectedPedido({ ...selectedPedido, raw_status: nextRaw, status_kanban: mapKanbanStatus(nextRaw) })
        }
      }
    } catch(err) { console.error(err) }
  }

  const handleCancelPedido = async () => {
    if (!cancelModalPedido || !cancelReason.trim()) return
    try {
      const { error } = await supabase.from(cancelModalPedido.tipo_tabela).update({ status: 'cancelado' }).eq('id', cancelModalPedido.id)
      if (!error) {
        await supabase.from('historico_status').insert({
          pedido_id: cancelModalPedido.id,
          origem_tabela: cancelModalPedido.tipo_tabela,
          status_anterior: cancelModalPedido.raw_status,
          status_novo: 'cancelado',
          motivo_cancelamento: cancelReason.trim()
        })
        fetchPedidos()
        setCancelModalPedido(null)
        setCancelReason('')
      }
    } catch(err) { console.error(err) }
  }

  // Agrupamento em colunas
  const columnsData = useMemo(() => {
    const cols: Record<string, UnifiedPedido[]> = {
      novo: [], em_preparo: [], saiu_entrega: [], entregue: [], cancelado: []
    }
    pedidos.forEach(p => cols[p.status_kanban].push(p))
    return cols
  }, [pedidos])

  const getCanalIcon = (canal: string) => {
    switch(canal) {
      case 'app': return 'phone_iphone'
      case 'balcao': return 'storefront'
      case 'entrega': return 'two_wheeler'
      case 'mesa': return 'table_restaurant'
      default: return 'public'
    }
  }

  return (
    <div className="h-[calc(100vh-80px)] md:h-screen w-full flex flex-col p-4 md:p-8 animate-fade-in bg-background">
      {/* Header com os botões solicitados e filtros futuramente */}
      <header className="flex flex-col md:flex-row justify-between items-start md:items-end mb-8 gap-4 shrink-0">
        <div>
          <h1 className="text-4xl font-headline font-bold text-on-surface tracking-tighter">Kanban de Pedidos</h1>
          <p className="text-on-surface-variant font-body mt-1">Gerenciamento em tempo real do fluxo de cozinha e entrega.</p>
        </div>
        <div className="flex gap-4">
           {/* Filtro simples placeholder */}
           <div className="bg-surface-container/50 px-4 py-2 rounded-xl border border-outline-variant/10 text-sm flex items-center gap-2 text-on-surface-variant">
             <span className="material-symbols-outlined text-lg">filter_alt</span>
             Filtros rápidos (Em Breve)
           </div>
        </div>
      </header>

      {/* Grid horizontal unificado com scroll via layout grid - Semelhante Módulo 1 */}
      <div className="flex-1 w-full flex gap-6 overflow-x-auto pb-4 custom-scrollbar items-stretch snap-x snap-mandatory">
        {COLUMNS.map(col => {
          const colPedidos = columnsData[col.id] || []

          return (
            <div key={col.id} className="min-w-[340px] max-w-[380px] w-full flex flex-col snap-start h-full max-h-full">
               {/* Cabeçalho da coluna fixo */}
               <div className={`shrink-0 flex justify-between items-center p-4 rounded-t-2xl border-t-4 ${col.color} ${col.headerBg} border-x border-x-outline-variant/5 border-b border-b-outline-variant/10`}>
                 <h2 className={`font-headline font-bold text-lg ${col.textColor}`}>{col.title}</h2>
                 <span className={`w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm bg-background border ${col.color} text-on-surface shadow-md`}>
                   {colPedidos.length}
                 </span>
               </div>

               {/* Scroll Independente */}
               <div className="flex-1 overflow-y-auto space-y-4 p-4 bg-surface-container-low/30 border-x border-b border-outline-variant/5 rounded-b-2xl no-scrollbar relative min-h-[300px]">
                 {loading ? (
                    <div className="absolute inset-0 flex items-center justify-center text-primary-container animate-pulse">
                      Carregando...
                    </div>
                 ) : colPedidos.length === 0 ? (
                    <div className="text-center py-10 opacity-30 text-sm font-bold flex flex-col items-center gap-2">
                       <span className="material-symbols-outlined text-4xl">inventory_2</span>
                       Vazio
                    </div>
                 ) : (
                   colPedidos.map(pedido => {
                     // Lógica visual do card requerida
                     const minutesElapsed = differenceInMinutes(currentTime, parseISO(pedido.created_at))
                     let timeClass = 'text-on-surface-variant'
                     let pingTime = false

                     if (minutesElapsed >= 30 && pedido.status_kanban !== 'entregue' && pedido.status_kanban !== 'cancelado') {
                       timeClass = 'text-red-500 font-bold'
                       pingTime = true
                     } else if (minutesElapsed >= 15 && pedido.status_kanban === 'novo') {
                       timeClass = 'text-yellow-400 font-bold'
                     }

                     const isCancelled = pedido.status_kanban === 'cancelado'

                     return (
                       <div key={pedido.id} className={`bg-surface p-5 rounded-2xl border ${isCancelled ? 'border-error/20 opacity-60' : 'border-outline-variant/10 hover:border-primary/30'} shadow-lg transition-all animate-slide-up group flex flex-col gap-4 relative overflow-hidden`} >

                          {/* Faixa colorida top se status atrasado (Módulo 1) */}
                          {pingTime && <div className="absolute top-0 left-0 right-0 h-1 bg-red-500 animate-pulse" />}

                          {/* Cabeçalho Card */}
                          <div className="flex justify-between items-start">
                             <div className="flex flex-col gap-1">
                                <span className={`text-[10px] font-bold uppercase tracking-widest ${col.textColor}`}>#{String(pedido.numero).padStart(4, '0')}</span>
                                <h3 className="font-headline font-bold text-lg text-on-surface leading-tight max-w-[200px] truncate" title={pedido.cliente_nome}>
                                  {pedido.cliente_nome}
                                </h3>
                             </div>

                             <div className="flex items-center gap-2">
                               {pingTime && <span className="w-2 h-2 rounded-full bg-red-500 animate-ping absolute top-4 right-16" />}
                               <div className={`px-2 py-1 rounded-lg bg-surface-container flex items-center gap-1.5 text-xs ${timeClass}`}>
                                  <span className="material-symbols-outlined text-[14px]">schedule</span>
                                  <span>{minutesElapsed}m</span>
                               </div>
                             </div>
                          </div>

                          {/* Info secundária (Items resumos e canal) */}
                          <div className="grid grid-cols-[1fr_auto] gap-2 p-3 bg-surface-container/40 rounded-xl items-center">
                             <div className="flex flex-col gap-1">
                                {pedido.itens.slice(0, 2).map((it, i) => (
                                   <p key={i} className="text-xs text-on-surface-variant line-clamp-1 break-all">
                                      <span className="font-bold text-on-surface/60">{it.qtd}x</span> {it.nome} {it.variacao ? ` - ${it.variacao}` : ''}
                                   </p>
                                ))}
                                {pedido.itens.length > 2 && (
                                   <p className="text-[10px] font-bold text-primary opacity-60 mt-1">+{pedido.itens.length - 2} mais</p>
                                )}
                             </div>
                             <div className="flex flex-col items-end gap-1 border-l border-outline-variant/10 pl-3">
                                <span className="material-symbols-outlined text-on-surface-variant/40" title={pedido.canal}>{getCanalIcon(pedido.canal)}</span>
                                <span className="text-[9px] uppercase font-bold tracking-widest opacity-50">{pedido.forma_pagamento}</span>
                             </div>
                          </div>

                          {/* Footer Card (Botoes e Total) */}
                          <div className="flex justify-between items-center mt-2">
                            <span className="text-green-400 font-headline font-bold text-lg">
                              R$ {pedido.total.toFixed(2)}
                            </span>

                            <div className="flex gap-2">
                              {!isCancelled && pedido.status_kanban !== 'entregue' && (
                                <>
                                  <button onClick={() => setCancelModalPedido(pedido)} className="w-9 h-9 flex items-center justify-center rounded-xl bg-surface-container hover:bg-error/10 hover:text-error text-on-surface-variant transition-colors" title="Cancelar">
                                    <span className="material-symbols-outlined text-[18px]">close</span>
                                  </button>
                                  <button 
                                    onClick={() => handleAvançarStatus(pedido)}
                                    className={`h-9 px-4 flex items-center justify-center rounded-xl text-sm font-bold shadow-lg transition-transform hover:scale-105 active:scale-95 ${col.textColor.replace('text', 'bg').replace('500', '500/10')} ${col.textColor}`}
                                    title="Avançar"
                                  >
                                    Avançar
                                  </button>
                                </>
                              )}

                              <button onClick={() => setSelectedPedido(pedido)} className="w-9 h-9 flex items-center justify-center rounded-xl bg-surface-container hover:bg-primary-container hover:text-primary transition-colors" title="Ver Detalhes">
                                <span className="material-symbols-outlined text-[18px]">open_in_new</span>
                              </button>
                            </div>
                          </div>

                       </div>
                     )
                   })
                 )}
               </div>
            </div>
          )
        })}
      </div>

      {/* Modal Cancelamento */}
      {cancelModalPedido && (
         <div className="fixed inset-0 z-[100] bg-black/60 flex items-center justify-center p-4">
           <div className="bg-surface p-6 rounded-3xl w-full max-w-sm border border-error/20 flex flex-col gap-4 animate-fade-in shadow-2xl">
              <h2 className="text-xl font-headline font-bold text-error flex items-center gap-2">
                 <span className="material-symbols-outlined">warning</span>
                 Cancelar Pedido
              </h2>
              <p className="text-sm text-on-surface-variant">
                 Qual o motivo do cancelamento para o pedido #{String(cancelModalPedido.numero).padStart(4, '0')}?
              </p>
              <textarea 
                 value={cancelReason}
                 onChange={e => setCancelReason(e.target.value)}
                 className="w-full bg-surface-container rounded-xl p-3 text-sm text-on-surface border border-outline-variant/10 focus:border-error outline-none resize-none min-h-[100px]"
                 placeholder="Diga o motivo para registro..."
              />
              <div className="flex justify-end gap-3 mt-2">
                 <button onClick={() => {setCancelModalPedido(null); setCancelReason('')}} className="px-4 py-2 rounded-xl text-on-surface-variant hover:bg-surface-container font-bold text-sm transition-colors">Voltar</button>
                 <button onClick={handleCancelPedido} disabled={!cancelReason.trim()} className="px-4 py-2 rounded-xl bg-error hover:bg-error/80 text-on-error font-bold text-sm transition-colors disabled:opacity-50">Confirmar</button>
              </div>
           </div>
         </div>
      )}

      {/* Drawer Detalhes */}
      {selectedPedido && (
         <>
           <div className="fixed inset-0 z-[90] bg-black/40 backdrop-blur-sm transition-opacity" onClick={() => setSelectedPedido(null)} />
           <div className="fixed right-0 top-0 bottom-0 w-full md:w-[450px] bg-surface z-[100] border-l border-outline-variant/10 shadow-2xl animate-slide-left flex flex-col">
              <div className="p-6 border-b border-outline-variant/5 flex justify-between items-center bg-surface-container-low/30">
                 <div>
                   <h2 className="text-2xl font-headline font-bold text-on-surface">Pedido #{String(selectedPedido.numero).padStart(4, '0')}</h2>
                   <div className="flex gap-2 mt-1 items-center">
                     <span className="text-[10px] tracking-widest uppercase bg-primary-container text-primary px-2 py-0.5 rounded-md font-bold">{selectedPedido.canal}</span>
                     <span className="text-xs text-on-surface-variant">{format(parseISO(selectedPedido.created_at), "dd/MM 'às' HH:mm", {locale: ptBR})}</span>
                   </div>
                 </div>
                 <button onClick={() => setSelectedPedido(null)} className="w-10 h-10 rounded-full bg-surface-container hover:bg-surface-container-high flex items-center justify-center text-on-surface-variant transition-colors">
                    <span className="material-symbols-outlined">close</span>
                 </button>
              </div>

              <div className="flex-1 overflow-y-auto p-6 space-y-8 no-scrollbar">
                 {/* Cliente */}
                 <section className="space-y-3">
                    <h3 className="text-xs font-bold uppercase tracking-widest text-on-surface-variant/40 flex items-center gap-2">
                       <span className="material-symbols-outlined text-[16px]">person</span> Cliente
                    </h3>
                    <div className="bg-surface-container/30 p-4 rounded-2xl border border-outline-variant/5">
                       <p className="font-headline font-bold text-lg text-on-surface">{selectedPedido.cliente_nome}</p>
                       <p className="text-sm text-on-surface-variant mt-1">{selectedPedido.cliente_telefone || 'Sem telefone'}</p>
                    </div>
                 </section>

                 {/* Endereço */}
                 {selectedPedido.endereco_entrega && (
                    <section className="space-y-3">
                       <h3 className="text-xs font-bold uppercase tracking-widest text-on-surface-variant/40 flex items-center gap-2">
                          <span className="material-symbols-outlined text-[16px]">location_on</span> Endereço
                       </h3>
                       <div className="bg-surface-container/30 p-4 rounded-2xl border border-outline-variant/5 flex justify-between items-start gap-4">
                          <p className="text-sm text-on-surface leading-relaxed">{selectedPedido.endereco_entrega}</p>
                          <a target="_blank" rel="noreferrer" href={`https://maps.google.com/?q=${encodeURIComponent(selectedPedido.endereco_entrega)}`} className="shrink-0 w-10 h-10 flex items-center justify-center rounded-xl bg-primary/10 text-primary hover:bg-primary/20 transition-colors">
                             <span className="material-symbols-outlined text-[20px]">map</span>
                          </a>
                       </div>
                    </section>
                 )}

                 {/* Itens */}
                 <section className="space-y-3">
                    <h3 className="text-xs font-bold uppercase tracking-widest text-on-surface-variant/40 flex items-center gap-2">
                       <span className="material-symbols-outlined text-[16px]">restaurant_menu</span> Pedido
                    </h3>
                    <div className="bg-surface-container/30 p-4 rounded-2xl border border-outline-variant/5 space-y-3">
                       {selectedPedido.itens.map((it: any, i: number) => (
                          <div key={i} className="flex justify-between items-start gap-3 border-b border-outline-variant/5 pb-3 mb-3 last:border-0 last:pb-0 last:mb-0">
                             <div>
                               <p className="font-bold text-on-surface">{it.qtd}x {it.nome}</p>
                               {it.variacao && <p className="text-xs text-secondary mt-0.5">{it.variacao}</p>}
                               {it.obs && <p className="text-[11px] text-on-surface-variant/60 mt-1 italic">Obs: {it.obs}</p>}
                             </div>
                          </div>
                       ))}
                    </div>
                 </section>
              </div>

              {/* Fixado Embaixo */}
              <div className="p-6 border-t border-outline-variant/10 bg-surface">
                 <div className="flex justify-between items-center mb-6">
                    <span className="text-sm text-on-surface-variant uppercase tracking-widest font-bold">Pagamento <br/><span className="text-on-surface">{selectedPedido.forma_pagamento}</span></span>
                    <span className="text-3xl font-headline font-bold text-green-400">R$ {selectedPedido.total.toFixed(2)}</span>
                 </div>
                 {selectedPedido.status_kanban !== 'cancelado' && selectedPedido.status_kanban !== 'entregue' && (
                    <button onClick={() => { handleAvançarStatus(selectedPedido) }} className="w-full h-14 bg-primary hover:bg-primary/90 text-on-primary font-bold rounded-2xl text-lg transition-transform active:scale-[0.98] shadow-[0_0_20px_rgba(255,86,55,0.3)]">
                      Avançar Pedido
                    </button>
                 )}
              </div>
           </div>
         </>
      )}

    </div>
  )
}
